mapper.select:
SELECT
    p.id, p.plan_code, p.plan_name, p.description, p.template_name,
    p.start_date, p.end_date, p.status,
    p.total_checks, p.total_records, p.total_deduction_score,
    p.enable_weight, p.creator_name, p.created_at
FROM check_plans p
WHERE p.deleted = 0

    AND p.plan_name LIKE CONCAT('%', #{query.planName}, '%')


    AND p.template_id = #{query.templateId}


    AND p.status = #{query.status}


    AND p.start_date >= #{query.startDateFrom}


    AND p.start_date <= #{query.startDateTo}

ORDER BY p.created_at DESC
